PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#> 
SELECT ?label WHERE { GRAPH <urn:doid> { obo:DOID_4 rdfs:label ?label . } }

PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#> 
SELECT ?subclass ?label WHERE { GRAPH <urn:doid> { ?subclass rdfs:subClassOf obo:DOID_14566 . ?subclass rdfs:label ?label . } }

PREFIX hpoa: <http://example.org/hpoa/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#> 
SELECT DISTINCT ?phenotype_label WHERE { GRAPH <urn:hpoa> { ?marfan hpoa:source_id "OMIM:154700"; hpoa:has_phenotype ?pheno . ?eds hpoa:source_id "OMIM:130000"; hpoa:has_phenotype ?pheno . } GRAPH <urn:hpo> { ?pheno rdfs:label ?phenotype_label . } }
